<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('projects.manage');if(vp3_method()==='POST'){vp3_verify_csrf();$id=(int)vp3_input('id');$status=vp3_input('status');if(in_array($status,['under_review','approved','revision_requested','archived'],true)){vp3_db()->prepare('UPDATE project_briefs SET status=?,reviewed_at=NOW(),reviewed_by_admin_id=?,updated_at=NOW() WHERE id=?')->execute([$status,$admin['id'],$id]);vp3_audit('admin',(int)$admin['id'],'project_brief.reviewed','project_brief',(string)$id,['status'=>$status]);}vp3_redirect('admin/project-briefs.php');}$rows=[];try{$rows=vp3_db()->query("SELECT pb.*,c.name customer_name,c.email customer_email FROM project_briefs pb JOIN customers c ON c.id=pb.customer_id ORDER BY FIELD(pb.status,'submitted','under_review','revision_requested','approved','draft','archived'),pb.updated_at DESC")->fetchAll();}catch(Throwable){}$pageTitle='Project Briefs';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Creative intake</span><h1>Project briefs</h1><p>Review story concepts, audiences, content formats, launch goals, service needs, and hosting preferences.</p></div></div><div class="brief-review-grid"><?php foreach($rows as $b):?><article class="card"><div class="project-card-top"><span class="badge <?=vp3_e($b['status'])?>"><?=vp3_e(str_replace('_',' ',$b['status']))?></span><small><?=vp3_e($b['updated_at'])?></small></div><h2><?=vp3_e($b['project_name'])?></h2><p><strong><?=vp3_e($b['customer_name'])?></strong> · <?=vp3_e($b['customer_email'])?></p><p><?=vp3_e($b['concept_summary'])?></p><dl class="detail-list"><dt>Audience</dt><dd><?=vp3_e($b['audience_summary'])?></dd><dt>Launch goal</dt><dd><?=vp3_e($b['launch_goals'])?></dd><dt>Target</dt><dd><?=vp3_e($b['target_launch_date']?:'Not set')?></dd><dt>Hosting</dt><dd><?=vp3_e($b['hosting_preference'])?></dd></dl><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="id" value="<?=(int)$b['id']?>"><select name="status"><?php foreach(['under_review','approved','revision_requested','archived'] as $v):?><option <?=$b['status']===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select><button class="button small">Update review</button></form><?php if($b['status']==='approved'):?><a class="button small secondary" href="project.php?brief_id=<?=(int)$b['id']?>">Create project</a><?php endif;?></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><p>No project briefs.</p></div><?php endif;?></div>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
